M = int(input())
tasks = input().split()
action = input().split()

if action[0] == "add":
    task = action[1]
    tasks.append(task)
elif action[0] == "insert":
    index = int(action[1])
    task = action[2]
    if index <= len(tasks):
        tasks.insert(index, task)
elif action[0] == "remove":
    task = action[1]
    if task in tasks:
        tasks.remove(task)
elif action[0] == "clear":
    tasks.clear()
    print("All tasks cleared")

if action[0] != "clear":
    for task in tasks:
        print(task, end=" ")
